DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PGchoicemacros.pl",
  "parserCheckboxList.pl",
  "contextForm.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
Context("Numeric");
Context()->variables->are(x=>'Real',y=>'Real',z=>'Real',r=>'Real',q=>'Real',p=>'Real',V=>'Real',);
Context()->noreduce('(-x)-y');
@allvars=('x','y','z','r','q','p','V');

@var=(
    (@allvars)[NchooseK(7, 2)],
    list_random(@allvars),
    (@allvars)[NchooseK(7, 2)],
    list_random(@allvars),
    (@allvars)[NchooseK(7,2)],
    list_random(@allvars),
);
@left=(
    Formula(random(1, 9) . "$var[0]^2 + " . non_zero_random(-9,9,1) . $var[1])->reduce,
    Formula(random(-5, 5))->reduce,
    Formula(random(1, 9) . "$var[3]^2 + " . non_zero_random(-9,9,1) . "$var[4]^2")->reduce,
    Formula(non_zero_random(-9, 9, 0.1) . $var[0])->reduce,
    Formula(random(-200, 200))->reduce,
    Formula('sqrt(' . random(2, 9) . "$var[3]) + " . non_zero_random(-19, 19))->reduce,
);
@right=(
    Compute(random(-99, 99)),
    Formula(non_zero_random(-9, 9) . '+' . non_zero_random(-19, 19) . $var[2])->reduce,
    Compute(1),
    Compute(random(-99, 99)),
    Formula(non_zero_random(-999, 999) . "$var[1] + " . non_zero_random(-999, 999) . $var[2])->reduce,
    Compute(non_zero_random(-9, 9)),
);
@symbol = map{(random(0, 1)) ? '=' : list_random('\lt', '\gt', '\leq', '\geq', '\neq')} (0..5);
@type = map{($_ eq '=') ? 'equation' : 'inequality'} (@symbol);
@eq = map{$BM . $left[$_]->TeX . $symbol[$_] . $right[$_]->TeX . $EM} (0..5);
$correct = ($var[1] == $var[2]) ? [1,3,4] : [1,3];
$options = CheckboxList([~~@eq, "None of the above"], $correct);

############################################################
# Body
############################################################

BEGIN_PGML
Select the equations/inequalities that are linear with one variable.

[_]{$options}{5}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
